namespace InventoryApp.Services;

public record EquipmentItem(int Id, string Name, string Location, DateTime LastInspected);

public class EquipmentService
{
    public async Task<List<EquipmentItem>> GetEquipmentAsync()
    {
        // Simulate network/database latency
        await Task.Delay(500);

        return new List<EquipmentItem>
        {
            new(1, "Hydraulic Press", "Building A", new DateTime(2026, 3, 15)),
            new(2, "CNC Lathe", "Building B", new DateTime(2026, 4, 22)),
            new(3, "Forklift #7", "Warehouse", new DateTime(2026, 5, 1)),
            new(4, "Conveyor Belt Motor", "Building A", new DateTime(2026, 2, 10)),
            new(5, "Air Compressor", "Maintenance Shop", new DateTime(2026, 1, 30)),
            new(6, "Welding Station 3", "Building C", new DateTime(2025, 12, 18)),
            new(7, "Overhead Crane", "Warehouse", new DateTime(2026, 4, 5)),
            new(8, "Drill Press", "Building B", new DateTime(2026, 5, 12)),
        };
    }
}

@page "/inventory"
@using InventoryApp.Services
@using Microsoft.AspNetCore.Components.Web
@rendermode InteractiveServer
@inject EquipmentService EquipmentService
@inject PersistentComponentState ApplicationState
@implements IDisposable

<PageTitle>Inventory</PageTitle>

<h1>Equipment Inventory</h1>

@if (_items is null)
{
    <p><em>Loading inventory...</em></p>
}
else
{
    <table class="table">
        <thead>
            <tr>
                <th>Id</th>
                <th>Name</th>
                <th>Location</th>
                <th>Last Inspected</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var item in _items)
            {
                <tr>
                    <td>@item.Id</td>
                    <td>@item.Name</td>
                    <td>@item.Location</td>
                    <td>@item.LastInspected.ToShortDateString()</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<EquipmentItem>? _items;
    private PersistingComponentStateSubscription _persistingSubscription;

    protected override async Task OnInitializedAsync()
    {
        _persistingSubscription = ApplicationState.RegisterOnPersisting(PersistData);

        // If state was persisted during prerender, restore it instead of fetching again
        if (ApplicationState.TryTakeFromJson<List<EquipmentItem>>("inventory", out var restored))
        {
            _items = restored;
        }
        else
        {
            _items = await EquipmentService.GetEquipmentAsync();
        }
    }

    private Task PersistData()
    {
        ApplicationState.PersistAsJson("inventory", _items);
        return Task.CompletedTask;
    }

    public void Dispose()
    {
        _persistingSubscription.Dispose();
    }
}

